def number_to_words(num: int) -> str:
    if num == 0:
        return 'Zero'

    ones = ['', 'One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven', 'Eight', 'Nine']
    teens = ['Ten', 'Eleven', 'Twelve', 'Thirteen', 'Fourteen', 'Fifteen',
             'Sixteen', 'Seventeen', 'Eighteen', 'Nineteen']
    tens_words = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty',
                  'Sixty', 'Seventy', 'Eighty', 'Ninety']
    units = ['', 'Thousand', 'Million', 'Billion']

    def convert_less_than_thousand(n: int) -> str:
        if n == 0:
            return ''
        if n < 10:
            return ones[n] + ' '
        if n < 20:
            return teens[n - 10] + ' '
        if n < 100:
            return tens_words[n // 10] + ' ' + convert_less_than_thousand(n % 10)
        return ones[n // 100] + ' Hundred ' + convert_less_than_thousand(n % 100)

    result = ''
    i = 0
    while num > 0:
        if num % 1000 != 0:
            result = convert_less_than_thousand(num % 1000) + units[i] + ' ' + result
        num //= 1000
        i += 1

    return result.strip()
